parameters.functionCode:
const payload = $input.item.json;

const cliente = payload.cliente || 'GERAL';
const principios = payload.principios || [];
const friccoes = payload.friccoes || [];
const dividas = payload.dividas || [];
const data = payload.data || new Date().toISOString().substring(0, 10);
const hora = payload.hora || new Date().toTimeString().substring(0, 5);

const resumoPrincipios = principios.length > 0 
  ? principios.map((p, i) => `${i+1}. ${p}`).join('\n')
  : 'Nenhum principio novo esta sessao';

const resumoFriccoes = friccoes.length > 0
  ? friccoes.map((f, i) => `${i+1}. ${f}`).join('\n')
  : 'Nenhuma friccao registrada';

return [{
  json: {
    cliente,
    principios,
    friccoes,
    dividas,
    data,
    hora,
    resumoPrincipios,
    resumoFriccoes,
    totalPrincipios: principios.length,
    totalFriccoes: friccoes.length,
    totalDividas: dividas.length
  }
}];

